'use client';
import { useState } from 'react';
import Sidebars from '@/components/ui/Sidebars';
import DashboardHeader from '@/components/ui/DashboardHeader';

const HostLayout = ({ children }: { children: React.ReactNode }) => {
  const [sidebarOpen, setSidebarOpen] = useState(true);

  return (
    <div className='flex h-screen bg-gray-50'>
      <div className='fixed inset-y-0 left-0 w-64 z-40'>
        <Sidebars
          sidebarOpen={sidebarOpen}
          setSidebarOpen={setSidebarOpen}
        />
      </div>
      {/* main content */}
      <div className='flex-1 overflow-y-auto scrollbar-hide ml-0 md:ml-64'>
        <DashboardHeader
          sidebarOpen={sidebarOpen}
          setSidebarOpen={setSidebarOpen}
        />
        <main className='p-6'>{children}</main>
      </div>
    </div>
  );
};

export default HostLayout;
