'use client';
import Link from 'next/link';
import { useAuth } from '@/context/AuthContext';
import { adminSidbarItems, hostSidbarItems } from '@/constants/navItems';
import { LogOut } from 'lucide-react';
import { AnimatePresence, motion } from 'framer-motion';

export interface SidebarProps {
  sidebarOpen: boolean;
  setSidebarOpen: (open: boolean) => void;
}

const Sidebars = ({ sidebarOpen, setSidebarOpen }: SidebarProps) => {
  const { logout, userRole } = useAuth();
  const handleLogout = () => {
    logout();
  };

  return (
    <AnimatePresence>
      {sidebarOpen && (
        <motion.aside
          initial={{ x: -300, opacity: 0 }}
          animate={{ x: 0, opacity: 1 }}
          exit={{ x: -300, opacity: 0 }}
          transition={{ type: 'spring', damping: 25 }}
          className={`w-64 h-full overflow-y-auto bg-gradient-to-br from-purple-950 via-purple-900 to-pink-900 text-white shadow-2xl ring-1 ring-white/10`}
        >
          <div className='h-full flex flex-col'>
            <div className='p-4 border-b'>
              <h1 className='text-xl font-bold'>UniJoy {userRole}</h1>
            </div>

            <nav className='flex-1 p-4 space-y-2'>
              {userRole === 'admin'
                ? adminSidbarItems.map((item, index) => (
                    <Link
                      key={index}
                      href={item.href}
                      className={`group flex items-center gap-3 p-3 rounded-xl bg-white/0 hover:bg-white/5 transition-all ring-1 ring-white/5 hover:ring-white/10`}
                    >
                      <item.icon className='w-5 h-5 text-purple-200 group-hover:text-white transition-colors' />
                      <span className='text-purple-100 group-hover:text-white transition-colors'>
                        {item.label}
                      </span>
                    </Link>
                  ))
                : hostSidbarItems.map((item, index) => (
                    <Link
                      key={index}
                      href={item.href}
                      className={`group flex items-center gap-3 p-3 rounded-xl bg-white/0 hover:bg-white/5 transition-all ring-1 ring-white/5 hover:ring-white/10`}
                    >
                      <item.icon className='w-5 h-5 text-purple-200 group-hover:text-white transition-colors' />
                      <span className='text-purple-100 group-hover:text-white transition-colors'>
                        {item.label}
                      </span>
                    </Link>
                  ))}
            </nav>
            {/* Section Logout */}
            <div className='p-4 border-t mt-auto'>
              <button
                className={`group w-full flex items-center gap-3 p-3 rounded-xl bg-white/0 hover:bg-white/5 transition-all ring-1 ring-white/5 hover:ring-white/10`}
              >
                <LogOut className='w-5 h-5 text-purple-200 group-hover:text-white' />
                <span
                  onClick={handleLogout}
                  className='text-purple-100 group-hover:text-white'
                >
                  Logout
                </span>
              </button>
            </div>
          </div>
        </motion.aside>
      )}
    </AnimatePresence>
  );
};

export default Sidebars;
